const l=JSON.parse('{"key":"v-2dd57fc5","path":"/project/%E5%A4%A7%E6%96%87%E4%BB%B6%E4%B8%8A%E4%BC%A0.html","title":"大文件上传","lang":"zh-CN","frontmatter":{"title":"大文件上传","isTimeLine":true,"date":"2026-01-21T00:00:00.000Z","category":["前端"],"tag":["JavaScript","源码"]},"headers":[{"level":3,"title":"背景","slug":"背景","link":"#背景","children":[]},{"level":3,"title":"解决方案","slug":"解决方案","link":"#解决方案","children":[]},{"level":3,"title":"目前成熟的大文件上传方案","slug":"目前成熟的大文件上传方案","link":"#目前成熟的大文件上传方案","children":[]},{"level":3,"title":"实现","slug":"实现","link":"#实现","children":[]},{"level":3,"title":"难点","slug":"难点","link":"#难点","children":[]}],"git":{"createdTime":1773458982000,"updatedTime":1773458982000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":4.36,"words":1308},"filePathRelative":"project/大文件上传.md","localizedDate":"2026年1月21日","excerpt":"<h3> 背景</h3>\\n<ol>\\n<li>大文件是指传送大于100M的文件，容易遇到问题：1.前后端上传请求超时限制，一次性传输大小限制。 2.网络抖动等，失败后需要重新上传。为了避免上传速度很慢，传输中断等问题，需要使用切片上传的方式。</li>\\n<li>课件支持上传音频、视频、PPT、PDF等类型的课件；上传的音视频课件大于100M的文件，容易遇到上传速度很慢，传输中断，等待一段时间后传输失败等问题等问题</li>\\n</ol>\\n<h3> 解决方案</h3>\\n<ol>\\n<li>将要上传的大文件用<code>Blob.prototype.slice</code>分成许多大小相同的小块，利用http的可并发性同时上传多个切片。</li>\\n<li>所有小块上传完成后，服务器会把这些小块按照正确的顺序拼接起来，还原成完整的大文件。这样就从原本上传一个大文件变成并发多个小文件，减少了上传时间。</li>\\n<li>优点：1）可以加快上传速度：可以同时上传多个小块，充分利用网络的带宽。2）减少上传失败的风险：上传过程中出现了问题，只需要重新上传出错的那个小块。</li>\\n</ol>"}');export{l as data};
